body:
### Version

0.27

### On which OS did this happen?

Linux

### Reproduction Steps

Hi,

I am trying to synthesize a simple 4-bit ripple carry adder. Since abc does not support multi-output cells, it is needed to first extract the full adders from the design and then custom map them to my single bit full adder cell using the `techmap` command.

However, the problem is that, for some reason, the command `extract_fa` is only extracting 3 of the 4 full adders.

This is my Yosys script:

```
read_verilog full_adder.v

hierarchy -check -top full_adder

read_liberty -lib sky130_fd_sc_hd__tt_025C_1v80.lib

proc
opt_clean

alumacc
opt -fast

techmap
opt -fast
extract_fa -fa -v
techmap -map OpenLane/pdks/sky130A/libs.tech/openlane/sky130_fd_sc_hd/fa_map.v
opt -fast

abc -liberty sky130_fd_sc_hd__tt_025C_1v80.lib
opt -fast

check

write_verilog synth_fa.v

stat -liberty sky130_fd_sc_hd__tt_025C_1v80.lib
```

Is there anything wrong in my script that could be causing the issue?

Thanks in advance.

### Expected Behavior

Same module synthesized with another tool. 

```
module full_adder ( a, b, c_in, c_out, sum );
  input [3:0] a;
  input [3:0] b;
  output [3:0] sum;
  input c_in;
  output c_out;
  wire   n1, n2, n3;

  sky130_fd_sc_hd__fa_1 U1 ( .A(b[3]), .B(a[3]), .CIN(n1), .COUT(c_out), .SUM(
        sum[3]) );
  sky130_fd_sc_hd__fa_1 U2 ( .A(b[2]), .B(a[2]), .CIN(n2), .COUT(n1), .SUM(
        sum[2]) );
  sky130_fd_sc_hd__fa_1 U3 ( .A(b[1]), .B(a[1]), .CIN(n3), .COUT(n2), .SUM(
        sum[1]) );
  sky130_fd_sc_hd__fa_1 U4 ( .A(c_in), .B(b[0]), .CIN(a[0]), .COUT(n3), .SUM(
        sum[0]) );
endmodule
```

### Actual Behavior

Only uses 3 full adder cells. Instead of the fourth one, it needs 6 other cells.
 
```
(* top =  1  *)
(* src = "../../full_adder.v:1.1-10.10" *)
module full_adder(a, b, c_in, c_out, sum);
  wire _00_;
  wire _01_;
  wire _02_;
  wire _03_;
  (* force_downto = 32'd1 *)
  (* src = "../../full_adder.v:8.24-8.36|/usr/local/bin/../share/yosys/techmap.v:274.23-274.25" *)
  wire [4:0] _04_;
  (* src = "../../full_adder.v:1.33-1.34" *)
  input [3:0] a;
  wire [3:0] a;
  (* src = "../../full_adder.v:2.33-2.34" *)
  input [3:0] b;
  wire [3:0] b;
  (* src = "../../full_adder.v:3.27-3.31" *)
  input c_in;
  wire c_in;
  (* src = "../../full_adder.v:4.32-4.37" *)
  output c_out;
  wire c_out;
  (* src = "../../full_adder.v:5.38-5.41" *)
  output [3:0] sum;
  wire [3:0] sum;
  sky130_fd_sc_hd__nand2_1 _05_ (
    .A(b[3]),
    .B(a[3]),
    .Y(_03_)
  );
  sky130_fd_sc_hd__a21oi_1 _06_ (
    .A1(a[2]),
    .A2(_04_[1]),
    .B1(b[2]),
    .Y(_00_)
  );
  sky130_fd_sc_hd__o22ai_1 _07_ (
    .A1(b[3]),
    .A2(a[3]),
    .B1(_04_[1]),
    .B2(a[2]),
    .Y(_01_)
  );
  sky130_fd_sc_hd__o21ai_0 _08_ (
    .A1(_00_),
    .A2(_01_),
    .B1(_03_),
    .Y(c_out)
  );
  sky130_fd_sc_hd__xnor2_1 _09_ (
    .A(b[3]),
    .B(a[3]),
    .Y(_02_)
  );
  sky130_fd_sc_hd__xnor2_1 _10_ (
    .A(_04_[2]),
    .B(_02_),
    .Y(sum[3])
  );
  (* module_not_derived = 32'd1 *)
  (* src = "OpenLane/pdks/sky130A/libs.tech/openlane/sky130_fd_sc_hd/fa_map.v:17.28-17.75" *)
  sky130_fd_sc_hd__fa_1 _11_ (
    .A(a[2]),
    .B(b[2]),
    .CIN(_04_[1]),
    .COUT(_04_[2]),
    .SUM(sum[2])
  );
  (* module_not_derived = 32'd1 *)
  (* src = "OpenLane/pdks/sky130A/libs.tech/openlane/sky130_fd_sc_hd/fa_map.v:17.28-17.75" *)
  sky130_fd_sc_hd__fa_1 _12_ (
    .A(a[1]),
    .B(b[1]),
    .CIN(_04_[0]),
    .COUT(_04_[1]),
    .SUM(sum[1])
  );
  (* module_not_derived = 32'd1 *)
  (* src = "OpenLane/pdks/sky130A/libs.tech/openlane/sky130_fd_sc_hd/fa_map.v:17.28-17.75" *)
  sky130_fd_sc_hd__fa_1 _13_ (
    .A(a[0]),
    .B(b[0]),
    .CIN(c_in),
    .COUT(_04_[0]),
    .SUM(sum[0])
  );
  assign _04_[4:3] = { 1'h0, c_out };
endmodule

```

